// User function to add two numbers represented by linked lists
function addTwoNumbers(l1, l2) {
    let dummy = new Node(0);
    let current = dummy;
    let carry = 0;

    while (l1 !== null || l2 !== null || carry !== 0) {
        let sum = carry;

        if (l1 !== null) {
            sum += l1.data;
            l1 = l1.next;
        }

        if (l2 !== null) {
            sum += l2.data;
            l2 = l2.next;
        }

        carry = Math.floor(sum / 10);
        current.next = new Node(sum % 10);
        current = current.next;
    }

    return dummy.next;
}
